USE `111`;
-- =============================================================================
-- 第一部分：ODS 原始数据层 (Operational Data Store)
-- =============================================================================

-- 1.1 客户信用原始表 (ODS)
CREATE TABLE IF NOT EXISTS ods_customer_credit_raw (
    ods_id         VARCHAR(64) PRIMARY KEY, -- 幂等加载主键
    customer_id    VARCHAR(50),
    customer_name  VARCHAR(100),
    id_card_no     VARCHAR(18),
    phone_number   VARCHAR(20),
    credit_score   INT,
    credit_level   VARCHAR(10),
    loan_amount    DECIMAL(18, 2),
    loan_date      VARCHAR(20), 
    is_overdue     INT,
    create_time    TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- 1.2 期货交易原始表 (ODS)
CREATE TABLE IF NOT EXISTS ods_futures_trade_raw (
    ods_id         VARCHAR(64) PRIMARY KEY,
    trade_id       VARCHAR(50),
    customer_id    VARCHAR(50),
    trade_date     VARCHAR(20),
    futures_code   VARCHAR(20),
    futures_name   VARCHAR(50),
    trade_type     VARCHAR(10),
    trade_volume   INT,
    trade_price    DECIMAL(18, 4),
    trade_amount   DECIMAL(18, 2),
    commission     DECIMAL(18, 2),
    settle_date    VARCHAR(20),
    create_time    TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- 1.3 市场风险监测原始表 (ODS)
CREATE TABLE IF NOT EXISTS ods_market_risk_raw (
    ods_id         VARCHAR(64) PRIMARY KEY,
    risk_id        VARCHAR(50),
    monitor_date   VARCHAR(20),
    futures_code   VARCHAR(20),
    risk_indicator VARCHAR(50),
    indicator_value DECIMAL(18, 4),
    risk_level     VARCHAR(10),
    threshold      DECIMAL(18, 4),
    is_exceeded    INT,
    create_time    TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- 清空旧数据（仅用于演示环境的重复测试）
TRUNCATE TABLE ods_customer_credit_raw;
TRUNCATE TABLE ods_futures_trade_raw;
TRUNCATE TABLE ods_market_risk_raw;

-- 导入重构后的测试数据 (含脏数据、异常数据)
-- 此处内容由 ods_refined_data.sql 补全
-- ODS Refined Test Data














-- 2.1 清洗后客户信用表 (DWD)
CREATE TABLE IF NOT EXISTS dwd_customer_credit (
    customer_id    VARCHAR(50) PRIMARY KEY, -- 业务主键
    customer_name  VARCHAR(100),
    id_card_no     VARCHAR(18) UNIQUE,      -- 身份证唯一约束
    phone_number   VARCHAR(20),
    credit_score   INT,
    credit_level   VARCHAR(10),
    loan_amount    DECIMAL(18, 2),
    loan_date      DATE,                    -- 统一日期类型
    is_overdue     INT,
    update_time    TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
);

-- 2.2 期货交易合规明细表 (DWD)
CREATE TABLE IF NOT EXISTS dwd_futures_trade_valid (
    trade_id       VARCHAR(50) PRIMARY KEY, -- 业务主键
    customer_id    VARCHAR(50),
    trade_date     DATE NOT NULL,           -- 统一日期类型，且不能为空
    futures_code   VARCHAR(20),
    futures_name   VARCHAR(50),
    trade_type     VARCHAR(10),
    trade_volume   INT,
    trade_price    DECIMAL(18, 4),
    trade_amount   DECIMAL(18, 2),
    commission     DECIMAL(18, 2),
    settle_date    DATE,
    update_time    TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    INDEX idx_trade_date (trade_date),      -- 增加日期索引，加速 DWS 聚合
    INDEX idx_cust_futures (customer_id, futures_code)
);

-- 2.3 清洗后市场风险监测表 (DWD)
CREATE TABLE IF NOT EXISTS dwd_market_risk_clean (
    risk_id        VARCHAR(50) PRIMARY KEY,
    monitor_date   DATE NOT NULL,
    futures_code   VARCHAR(20),
    risk_indicator VARCHAR(50),
    indicator_value DECIMAL(18, 4),
    risk_level     VARCHAR(10),
    threshold      DECIMAL(18, 4),
    is_exceeded    INT,
    update_time    TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    INDEX idx_monitor_date (monitor_date)
);

-- 2.4 期货交易异常明细表 (DWD - 供风控排查)
CREATE TABLE IF NOT EXISTS dwd_futures_trade_exceptions (
    exception_id     VARCHAR(64) PRIMARY KEY,
    trade_id         VARCHAR(50),
    customer_id      VARCHAR(50),
    trade_date       DATE,
    futures_code     VARCHAR(20),
    exception_type   VARCHAR(100),
    exception_detail TEXT,
    raw_data_snapshot TEXT,
    process_time     TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- 2.5 数据质量问题明细表 (DWD - 供质量治理)
CREATE TABLE IF NOT EXISTS dwd_data_quality_issues (
    issue_id       VARCHAR(64) PRIMARY KEY,
    monitor_date   DATE,
    table_name     VARCHAR(100),
    column_name    VARCHAR(100),
    issue_type     VARCHAR(100),
    issue_value    TEXT,
    description    TEXT,
    process_time   TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- 2.6 客户信用数据清洗 (去重、修复评分、日期转换)
SELECT 
    customer_id,
    COALESCE(customer_name, 'Unknown') as customer_name,
    id_card_no,
    phone_number,
    CASE WHEN credit_score < 0 OR credit_score > 1000 THEN 500 ELSE credit_score END as credit_score,
    COALESCE(credit_level, 'C') as credit_level,
    ABS(loan_amount) as loan_amount,
    CASE WHEN loan_date REGEXP '^[0-9]{4}-[0-9]{2}-[0-9]{2}$' THEN CAST(loan_date AS DATE) ELSE NULL END as loan_date,
    COALESCE(is_overdue, 0) as is_overdue
FROM (
    -- 严格去重逻辑：同一客户取最新的记录
    SELECT *, ROW_NUMBER() OVER(PARTITION BY customer_id ORDER BY create_time DESC) as rn
    FROM ods_customer_credit_raw
    WHERE customer_id IS NOT NULL AND customer_id != 'NULL'
) t
WHERE rn = 1;

-- 2.7 期货交易数据核对与分流 (合规 -> Valid, 异常 -> Exceptions)
-- 2.7.1 记录异常明细 (供排查)
SELECT 
    SHA2(CONCAT(trade_id, trade_date, 'EXCEPTION'), 256) as exception_id,
    trade_id, customer_id, 
    CASE WHEN trade_date REGEXP '^[0-9]{4}-[0-9]{2}-[0-9]{2}$' THEN CAST(trade_date AS DATE) ELSE NULL END as trade_date,
    futures_code,
    CASE 
        WHEN customer_id IS NULL OR customer_id = 'NULL' THEN 'MISSING_CUSTOMER'
        WHEN ABS(trade_amount - (trade_volume * trade_price)) > 0.01 THEN 'AMOUNT_INCONSISTENT'
        WHEN trade_volume <= 0 THEN 'INVALID_VOLUME'
        ELSE 'OTHER'
    END as exception_type,
    CONCAT('Expected Amt:', trade_volume * trade_price, ', Actual Amt:', trade_amount) as exception_detail,
    CONCAT('Vol:', trade_volume, '|Price:', trade_price, '|Amt:', trade_amount) as raw_data_snapshot
FROM ods_futures_trade_raw
WHERE customer_id IS NULL OR customer_id = 'NULL'
   OR ABS(trade_amount - (trade_volume * trade_price)) > 0.01
   OR trade_volume <= 0;

-- 2.7.2 写入合规明细 
SELECT 
    trade_id, customer_id, CAST(trade_date AS DATE), futures_code, futures_name, trade_type, trade_volume, trade_price, trade_amount, commission, CAST(settle_date AS DATE)
FROM ods_futures_trade_raw
WHERE customer_id IS NOT NULL AND customer_id != 'NULL'
  AND ABS(trade_amount - (trade_volume * trade_price)) <= 0.01
  AND trade_volume > 0
  AND trade_date REGEXP '^[0-9]{4}-[0-9]{2}-[0-9]{2}$';

-- 2.8 市场风险监测清洗
SELECT 
    risk_id, CAST(monitor_date AS DATE), futures_code, risk_indicator, 
    CASE WHEN indicator_value < 0 THEN 0 ELSE indicator_value END as indicator_value,
    COALESCE(risk_level, 'LOW') as risk_level,
    threshold, is_exceeded
FROM ods_market_risk_raw
WHERE monitor_date REGEXP '^[0-9]{4}-[0-9]{2}-[0-9]{2}$';

-- =============================================
-- DWS
-- =============================================

-- 1. 业务指标日报表
CREATE TABLE IF NOT EXISTS dws_business_indicators (
    report_date             DATE,
    customer_id             VARCHAR(50),
    futures_code            VARCHAR(20),
    credit_level            VARCHAR(10),
    total_trade_volume      INT DEFAULT 0,
    total_holding_volume    INT DEFAULT 0,
    profit_loss_amount      DECIMAL(18,2) DEFAULT 0,
    credit_compliance_rate  DECIMAL(5,2) DEFAULT 0,
    market_risk_exposure    DECIMAL(18,4) DEFAULT 0,
    update_time             TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    PRIMARY KEY (report_date, customer_id, futures_code)
);

-- 2. 业务风险监控表
CREATE TABLE IF NOT EXISTS dws_risk_monitoring (
    monitor_id       VARCHAR(64) PRIMARY KEY,
    monitor_date     DATE,
    risk_type        VARCHAR(50),
    entity_type      VARCHAR(50),
    entity_id        VARCHAR(50),
    risk_description TEXT,
    risk_level       VARCHAR(10),
    INDEX idx_date (monitor_date)
);

-- 3. 数据质量异常明细表（你要的错误清单）
CREATE TABLE IF NOT EXISTS dws_data_quality_summary (
    monitor_date   DATE,
    table_name     VARCHAR(100),
    error_type     VARCHAR(100),
    error_id       VARCHAR(100),
    error_detail   VARCHAR(200),
    PRIMARY KEY (monitor_date, table_name, error_type, error_id)
);



-- 1. 业务指标表
    report_date, customer_id, futures_code, credit_level,
    total_trade_volume, total_holding_volume, profit_loss_amount,
    credit_compliance_rate, market_risk_exposure
)
WITH risk_daily AS (
    SELECT monitor_date, futures_code, AVG(indicator_value) AS market_risk_exposure
    FROM dwd_market_risk_clean GROUP BY monitor_date, futures_code
)
SELECT
    t.trade_date,
    t.customer_id,
    t.futures_code,
    MAX(c.credit_level),
    SUM(t.trade_volume),
    SUM(CASE WHEN t.trade_type='BUY' THEN t.trade_volume ELSE -t.trade_volume END),
    SUM(CASE WHEN t.trade_type='SELL' THEN t.trade_amount ELSE -t.trade_amount END),
    CASE WHEN MAX(c.credit_level) IN ('A','B') THEN 100 ELSE 60 END,
    IFNULL(AVG(r.market_risk_exposure), 0)
FROM dwd_futures_trade_valid t
LEFT JOIN dwd_customer_credit c ON t.customer_id = c.customer_id
LEFT JOIN risk_daily r ON t.trade_date = r.monitor_date AND t.futures_code = r.futures_code
GROUP BY t.trade_date, t.customer_id, t.futures_code;


-- 2. 业务风险监控（信用风险 + 市场风险 + 持仓风险）

SELECT
    SHA2(CONCAT(customer_id, CURDATE()),256),
    CURDATE(),
    'CREDIT_HIGH_RISK',
    'CUSTOMER',
    customer_id,
    CONCAT('客户信用=', credit_level, ' 高风险'),
    'HIGH'
FROM dwd_customer_credit
WHERE credit_level IN ('D','E')

UNION ALL

SELECT
    SHA2(CONCAT(futures_code, monitor_date, risk_indicator),256),
    monitor_date,
    'MARKET_RISK',
    'FUTURES',
    futures_code,
    CONCAT(risk_indicator, ' 超过阈值'),
    risk_level
FROM dwd_market_risk_clean
WHERE is_exceeded = 1

UNION ALL

SELECT
    SHA2(CONCAT(customer_id, futures_code, report_date),256),
    report_date,
    'HOLDING_RISK',
    'CUSTOMER',
    customer_id,
    CONCAT(futures_code, ' 持仓量过大'),
    'HIGH'
FROM dws_business_indicators
WHERE ABS(total_holding_volume) > 500;


-- 3. 数据质量表

SELECT CURDATE(), 'ods_futures_trade_raw', '客户ID为空', trade_id, '客户ID缺失'
FROM ods_futures_trade_raw WHERE customer_id IS NULL AND trade_id IS NOT NULL

UNION ALL
SELECT CURDATE(), 'ods_futures_trade_raw', '金额不一致', trade_id, '计算错误'
FROM ods_futures_trade_raw WHERE ABS(trade_amount-trade_volume*trade_price)>0.01 AND trade_id IS NOT NULL

UNION ALL
SELECT CURDATE(), 'ods_futures_trade_raw', '交易量异常', trade_id, '≤0'
FROM ods_futures_trade_raw WHERE trade_volume<=0 AND trade_id IS NOT NULL

UNION ALL
SELECT CURDATE(), 'ods_customer_credit_raw', '信用分异常', customer_id, '超出范围'
FROM ods_customer_credit_raw WHERE (credit_score<0 OR credit_score>1000) AND customer_id IS NOT NULL;